<template>
	<view class="complaint-page">
		<!-- 背景装饰 -->
		<view class="bg-blur"></view>

		<!-- 顶部返回栏 -->
		<view class="nav-bar">
			<view class="back-btn" @click="goBack">
				<text class="back-icon">←</text>
			</view>
			<text class="nav-title">投诉建议</text>
			<view class="placeholder"></view>
		</view>

		<!-- 表单卡片 -->
		<view class="form-card">
			<!-- 类型选择 -->
			<view class="type-select">
				<view
					class="type-item"
					:class="{ active: type === 'complaint' }"
					@click="type = 'complaint'"
				>
					投诉
				</view>
				<view
					class="type-item"
					:class="{ active: type === 'suggestion' }"
					@click="type = 'suggestion'"
				>
					建议
				</view>
			</view>

			<!-- 标题 -->
			<view class="form-item">
				<text class="label">标题</text>
				<input
					class="input"
					v-model="form.title"
					placeholder="请输入标题（必填）"
					placeholder-class="placeholder"
				/>
			</view>

			<!-- 内容 -->
			<view class="form-item">
				<text class="label">内容</text>
				<textarea
					class="textarea"
					v-model="form.content"
					placeholder="请详细描述您的问题或建议（必填）"
					placeholder-class="placeholder"
				/>
			</view>

			<!-- 联系方式 -->
			<view class="form-item">
				<text class="label">联系方式</text>
				<input
					class="input"
					v-model="form.contact"
					placeholder="手机号/邮箱（方便我们回复您）"
					placeholder-class="placeholder"
				/>
			</view>

			<!-- 图片上传 -->
			<view class="form-item">
				<text class="label">上传图片</text>
				<view class="image-list">
					<view class="image-item" v-for="(img, idx) in images" :key="idx">
						<image :src="img" mode="aspectFill" class="uploaded-img" @click="previewImage(idx)"></image>
						<view class="delete-btn" @click="deleteImage(idx)">×</view>
					</view>
					<view class="add-image" @click="chooseImage" v-if="images.length < 4">
						<text class="add-icon">+</text>
						<text class="add-text">上传图片</text>
					</view>
				</view>
				<text class="tip-text">最多上传4张图片，支持jpg/png格式</text>
			</view>

			<!-- 提交按钮 -->
			<view class="submit-btn" @click="submit">
				<text>提交反馈</text>
			</view>
		</view>

		<!-- 底部提示 -->
		<view class="tips">
			<text class="tips-text">* 您的反馈将帮助我们改进服务，我们承诺严格保密您的信息</text>
		</view>
	</view>
</template>

<script>
export default {
	data() {
		return {
			type: 'complaint', // complaint / suggestion
			form: {
				title: '',
				content: '',
				contact: ''
			},
			images: [] // 存储临时图片路径
		};
	},
	methods: {
		goBack() {
			uni.navigateBack();
		},
		chooseImage() {
			uni.chooseImage({
				count: 4 - this.images.length,
				sizeType: ['compressed'],
				sourceType: ['album', 'camera'],
				success: (res) => {
					this.images = [...this.images, ...res.tempFilePaths];
				}
			});
		},
		deleteImage(index) {
			this.images.splice(index, 1);
		},
		previewImage(index) {
			uni.previewImage({
				urls: this.images,
				current: this.images[index]
			});
		},
		submit() {
			// 简单验证
			if (!this.form.title.trim()) {
				uni.showToast({ title: '请填写标题', icon: 'none' });
				return;
			}
			if (!this.form.content.trim()) {
				uni.showToast({ title: '请填写内容', icon: 'none' });
				return;
			}
			// 模拟提交
			uni.showLoading({ title: '提交中...' });
			setTimeout(() => {
				uni.hideLoading();
				uni.showModal({
					title: '提交成功',
					content: '感谢您的反馈，我们会尽快处理。',
					showCancel: false,
					success: () => {
						// 可选：清空表单
						this.form = { title: '', content: '', contact: '' };
						this.images = [];
						// 延迟返回上一页
						setTimeout(() => {
							uni.navigateBack();
						}, 1500);
					}
				});
			}, 1000);
		}
	}
};
</script>

